function maxSubstringOccurrences(s, k) {
    const n = s.length;
    let res = 0;
    const freq = new Map();
    for (let i = 0; i < n; ++i) {
        const c = s.charAt(i);
        freq.set(c, (freq.get(c) || 0) + 1);
        if (freq.size <= k) {
            res = Math.max(res, freq.get(c));
        }
    }
    return (freq.size > k) ? 0 : res;
}
